def evaluate_expression(expr):
    tokens = []
    i = 0
    n = len(expr)
    while i < n:
        c = expr[i]
        if c.isspace():
            i += 1; continue
        if c in '+-*/()':
            tokens.append(c); i += 1; continue
        if c.isdigit() or c == '.':
            j = i
            while j < n and (expr[j].isdigit() or expr[j] == '.'): j += 1
            tokens.append(float(expr[i:j])); i = j; continue
        raise ValueError('bad char')
    pos = 0
    def peek(): return tokens[pos] if pos < len(tokens) else None
    def parse_expr():
        nonlocal pos
        val = parse_term()
        while peek() in ('+', '-'):
            op = tokens[pos]; pos += 1; rhs = parse_term()
            val = val + rhs if op == '+' else val - rhs
        return val
    def parse_term():
        nonlocal pos
        val = parse_factor()
        while peek() in ('*', '/'):
            op = tokens[pos]; pos += 1; rhs = parse_factor()
            val = val * rhs if op == '*' else val / rhs
        return val
    def parse_factor():
        nonlocal pos
        t = peek()
        if t == '+': pos += 1; return parse_factor()
        if t == '-': pos += 1; return -parse_factor()
        if t == '(':
            pos += 1; val = parse_expr(); pos += 1; return val
        pos += 1; return t
    return parse_expr()
